#include "brush.h"
#include <assert.h>
#include <sys/stat.h>
int main(int argc,char**argv){BrushPoint p[]={{500,520},{450,450},{390,395},{320,370},{250,370},{180,390},{130,450},{120,520},{155,585},{220,635},{300,650},{380,620},{440,570},{500,520},{560,465},{620,410},{700,370},{770,380},{830,420},{870,480},{875,545},{845,610},{790,660},{720,675},{650,655},{585,610},{540,560},{500,520}},right[]={{0,0},{100,0},{100,100}};char*d=brush_build_rounded_path(right,3,40);assert(d&&strcmp(d,"M 0 0 L 55 0 Q 100 0 100 45 L 100 100")==0);free(d);BrushArcPath arc=brush_prepare_arc_path(right,2,.5);assert(brush_sample_at(&arc,.5,40).angle==0);const char*input=argc>1?argv[1]:"assets/example.webp",*output=argc>2?argv[2]:"generated/c.svg";FILE*f=fopen(input,"rb");assert(f);fseek(f,0,SEEK_END);long n=ftell(f);rewind(f);uint8_t*bytes=(uint8_t*)malloc((size_t)n);assert(bytes&&fread(bytes,1,(size_t)n,f)==(size_t)n);fclose(f);BrushOptions o=brush_default_options();o.magic_gradient=true;char*svg=brush_render_svg(bytes,(size_t)n,"image/webp",1000,1000,p,sizeof p/sizeof*p,"🤝 best friends forever",o);assert(svg&&strstr(svg,"data:image/webp;base64,"));mkdir("generated",0755);f=fopen(output,"wb");assert(f);fwrite(svg,1,strlen(svg),f);fclose(f);printf("Wrote %s\n",output);free(svg);free(bytes);return 0;}
